    target_reviewer: reviewerLabel,
    workspace_url: reviewer.workspace_url || ctx.request?.slack_workspace_url || null,
    message_preview: text
  } } }];
}
try {
  await requestWithRetry({
    method: 'POST',
    url: hook,
    headers: { 'Content-Type': 'application/json' },
    body: { text },
    json: true,
    timeout: 30000
  });
