const incoming = $input.first().json;
if (incoming.failed_agent === 'WebhookAuthGate') {
  return [{ json: { ...incoming, feedback_loop: { mode: 'none', status: 'skipped_auth_failure', reason: 'Unauthorized request.' } } }];
}
let ctx = incoming;
let slackApproval = incoming?.data || incoming?.slack_approval || null;
try {
  const reviewItem = $('Human-in-the-loop review gate').first().json;
  if (reviewItem && reviewItem.run_id) {
    ctx = {
      ...reviewItem,
      ...incoming,
      request: reviewItem.request || incoming.request,
      agents: reviewItem.agents || incoming.agents,
      human_review: reviewItem.human_review || incoming.human_review,
      quality_gate: reviewItem.quality_gate || incoming.quality_gate,
      research_readiness: reviewItem.research_readiness || incoming.research_readiness,
      slack_notification: incoming.slack_notification || reviewItem.slack_notification || null,
      slack_approval: slackApproval
    };
  }
} catch (error) {
  ctx = { ...incoming, context_recovery_error: String(error.message || error) };
}
const feedback = ctx.request?.human_feedback || null;
const previousRunId = ctx.request?.previous_run_id || null;
const feedbackUrl = ctx.human_review?.feedback_webhook_url;
const approved = ctx.slack_approval?.approved;
let status = 'awaiting_feedback';
let nextStep = 'When the reviewer posts feedback to the feedback_webhook_url, the same agent pipeline restarts from the beginning.';
if (approved === true) {
  status = 'approved_by_human';
  nextStep = 'Evaluation run is approved. Final response can be archived or published.';
} else if (approved === false) {
  status = 'revision_requested_by_slack';
  nextStep = 'Reviewer selected revise. Post concrete revision feedback to the feedback_webhook_url to start a revised run.';
} else if (feedback) {
  status = 'feedback_ingested_and_pipeline_restarted';
  nextStep = 'This is a re-entry execution generated from human feedback.';
}
const revisedRequest = feedback
  ? `Revise previous run ${previousRunId || ctx.run_id} with evaluator feedback: ${feedback}`
  : null;
return [{ json: { ...ctx, feedback_loop: {
  mode: 'human_in_the_loop',
  reviewer: ctx.human_review?.reviewer || null,
  status,
  slack_approval: ctx.slack_approval || null,
  feedback_action: ctx.request?.feedback_action || (approved === false ? 'revise' : null),
  previous_run_id: previousRunId || null,
  feedback_webhook_url: feedbackUrl,
  received_feedback: feedback || null,
  revised_user_request: revisedRequest,
  next_step: nextStep
} } }];

