async function requestWithRetry(options, attempts = 3, baseDelayMs = 500) {
  let lastError;
  for (let i = 0; i < attempts; i += 1) {
    try {
      return await helpers.httpRequest(options);
    } catch (error) {
      lastError = error;
      const waitMs = baseDelayMs * Math.pow(2, i);
      await new Promise(resolve => setTimeout(resolve, waitMs));
    }
  }
  throw lastError;
}
if (ctx.failed) return [{ json: ctx }];
try {
  const scenarioId = ctx.request?.scenario_id || '';
  const url = scenarioId ? `${ctx.base_url}/agent/preflight?scenario_id=${encodeURIComponent(scenarioId)}` : `${ctx.base_url}/agent/preflight`;
  const data = await requestWithRetry({ method: 'GET', url, json: true, timeout: 30000 });
  const failed = data.status === 'failed';
  return [{ json: { ...ctx, preflight: data, failed, failed_agent: failed ? 'PreflightAgent' : ctx.failed_agent, error: failed ? 'Preflight failed: CARLA/n8n/OpenCDA readiness check did not pass' : ctx.error } }];
} catch (error) {
  return [{ json: { ...ctx, failed: true, failed_agent: 'PreflightAgent', error: String(error.message || error) } }];
}

